using System.Collections.Immutable; using Microsoft.CodeAnalysis; using Microsoft.CodeAnalysis.CSharp; using Xunit; namespace VisionaryCoder.Tooling.Generators.Tests; public sealed class EventGeneratorTests { private static ImmutableArray<SyntaxTree> GetCompilation(string source, string attributeSource) => ImmutableArray.Create(CSharpSyntaxTree.ParseText(attributeSource), CSharpSyntaxTree.ParseText(source)); private static Compilation CreateCompilation(ImmutableArray<SyntaxTree> trees) { var references = AppDomain.CurrentDomain.GetAssemblies().Where(a => !a.IsDynamic && a.Location.Length > 0).Select(a => MetadataReference.CreateFromFile(a.Location)).Distinct().ToArray(); return CSharpCompilation.Create("GeneratorTest").AddReferences(references).AddSyntaxTrees(trees); } private static (Compilation, IEnumerable<string>) RunGenerator(string source, string attributeSource = "") { var defaultAttribute = "namespace VisionaryCoder.Tooling.Shared.Attributes; [AttributeUsage(AttributeTargets.Class)] public sealed class DomainEventAttribute : Attribute {}"; var attr = string.IsNullOrEmpty(attributeSource) ? defaultAttribute : attributeSource; var trees = GetCompilation(source, attr); var compilation = CreateCompilation(trees); var generator = new EventGenerator(); var driver = CSharpGeneratorDriver.Create(generator); driver.RunGeneratorsAndUpdateCompilation(compilation, out var outputCompilation, out _); var sources = outputCompilation.SyntaxTrees.Skip(compilation.SyntaxTrees.Count()).Select(st => st.GetText().ToString()).ToList(); return (outputCompilation, sources); } [Fact] public void GeneratorExecutes() { var (_, s) = RunGenerator("using VisionaryCoder.Tooling.Shared.Attributes; namespace Events; [DomainEvent] public class UserCreated {}"); Assert.True(true); } [Fact] public void ProducesOutput() { var (_, s) = RunGenerator("using VisionaryCoder.Tooling.Shared.Attributes; namespace Events; [DomainEvent] public class UserCreated {}"); Assert.NotEmpty(s); } [Fact] public void ContainsEnvelopeRecord() { var (_, s) = RunGenerator("using VisionaryCoder.Tooling.Shared.Attributes; namespace Events; [DomainEvent] public class UserCreated {}"); Assert.Contains("record", s.First()); } [Fact] public void ContainsCorrelationId() { var (_, s) = RunGenerator("using VisionaryCoder.Tooling.Shared.Attributes; namespace Events; [DomainEvent] public class UserCreated {}"); Assert.Contains("CorrelationId", s.First()); } [Fact] public void ContainsCausationId() { var (_, s) = RunGenerator("using VisionaryCoder.Tooling.Shared.Attributes; namespace Events; [DomainEvent] public class UserCreated {}"); Assert.Contains("CausationId", s.First()); } [Fact] public void ContainsTimestamp() { var (_, s) = RunGenerator("using VisionaryCoder.Tooling.Shared.Attributes; namespace Events; [DomainEvent] public class UserCreated {}"); Assert.Contains("Timestamp", s.First()); } [Fact] public void ContainsCreateFactory() { var (_, s) = RunGenerator("using VisionaryCoder.Tooling.Shared.Attributes; namespace Events; [DomainEvent] public class UserCreated {}"); Assert.Contains("Create", s.First()); } [Fact] public void ContainsAutoGenHeader() { var (_, s) = RunGenerator("using VisionaryCoder.Tooling.Shared.Attributes; namespace Events; [DomainEvent] public class UserCreated {}"); Assert.Contains("auto-generated", s.First()); } [Fact] public void ContainsNullableDirective() { var (_, s) = RunGenerator("using VisionaryCoder.Tooling.Shared.Attributes; namespace Events; [DomainEvent] public class UserCreated {}"); Assert.Contains("#nullable", s.First()); } [Fact] public void IsDeterministic() { var (_, s1) = RunGenerator("using VisionaryCoder.Tooling.Shared.Attributes; namespace Events; [DomainEvent] public class UserCreated {}"); var (_, s2) = RunGenerator("using VisionaryCoder.Tooling.Shared.Attributes; namespace Events; [DomainEvent] public class UserCreated {}"); Assert.Equal(s1.First(), s2.First()); } [Fact] public void PreservesNamespace() { var (_, s) = RunGenerator("using VisionaryCoder.Tooling.Shared.Attributes; namespace Events.Orders; [DomainEvent] public class OrderCreated {}"); Assert.Contains("namespace Events.Orders", s.First()); } }
